changeSet.sql:
ALTER TABLE auth.permission ADD COLUMN id UUID;
UPDATE auth.permission SET id = gen_random_uuid();
ALTER TABLE auth.permission ALTER COLUMN id SET NOT NULL;

ALTER TABLE auth.role_permission ADD COLUMN permission_id UUID;
UPDATE auth.role_permission rp
  SET permission_id = p.id
  FROM auth.permission p
  WHERE rp.permission_name = p.name;
ALTER TABLE auth.role_permission ALTER COLUMN permission_id SET NOT NULL;

-- UNIQUE 제약: 이미 존재하면 삭제 후 재생성 (컬럼 구성이 다를 수 있으므로)
ALTER TABLE auth.role_permission DROP CONSTRAINT IF EXISTS uq_role_permission;
ALTER TABLE auth.role_permission ADD CONSTRAINT uq_role_permission UNIQUE (role_id, permission_id);

-- FK: 없을 때만 추가 (이전 부분 실행으로 이미 존재할 수 있음)
DO $$ BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.table_constraints
    WHERE constraint_schema = 'auth'
      AND constraint_name   = 'fk_role_permission_permission'
      AND table_name        = 'role_permission'
  ) THEN
    ALTER TABLE auth.role_permission ADD CONSTRAINT fk_role_permission_permission
      FOREIGN KEY (permission_id) REFERENCES auth.permission(id);
  END IF;
END $$;

-- 구 컬럼: 있을 때만 제거
ALTER TABLE auth.role_permission DROP COLUMN IF EXISTS permission_name;

-- 기존 PK(name) 제거 후 UUID PK로 교체
ALTER TABLE auth.permission DROP CONSTRAINT IF EXISTS permission_pkey;
ALTER TABLE auth.permission ADD CONSTRAINT permission_pkey PRIMARY KEY (id);

-- name UNIQUE 제약: 없을 때만 추가
DO $$ BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.table_constraints
    WHERE constraint_schema = 'auth'
      AND constraint_name   = 'uq_permission_name'
      AND table_name        = 'permission'
  ) THEN
    ALTER TABLE auth.permission ADD CONSTRAINT uq_permission_name UNIQUE (name);
  END IF;
END $$;

-- 타임스탬프 컬럼: 없을 때만 추가
ALTER TABLE auth.permission ADD COLUMN IF NOT EXISTS created_at TIMESTAMPTZ;
ALTER TABLE auth.permission ADD COLUMN IF NOT EXISTS updated_at TIMESTAMPTZ;
UPDATE auth.permission SET created_at = now() WHERE created_at IS NULL;
UPDATE auth.permission SET updated_at = now() WHERE updated_at IS NULL;
ALTER TABLE auth.permission ALTER COLUMN created_at SET NOT NULL;
ALTER TABLE auth.permission ALTER COLUMN updated_at SET NOT NULL;

ALTER TABLE auth.member_role DROP CONSTRAINT IF EXISTS uq_member_role;
ALTER TABLE auth.member_role DROP CONSTRAINT IF EXISTS uq_member_role_single;
ALTER TABLE auth.member_role ADD CONSTRAINT uq_member_role_single UNIQUE (member_id);
